import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { getRoomTypes } from '../api/rooms';

export default function HomePage() {
  const [roomTypes, setRoomTypes] = useState([]);
  const [typesLoading, setTypesLoading] = useState(true);
  const [roomTypeImages, setRoomTypeImages] = useState({});
  const [heroVisible, setHeroVisible] = useState(true);
  const [activeFeature, setActiveFeature] = useState(null);
  const heroRef = useRef(null);
  const featuresRef = useRef(null);

  // Fetch room types on component mount
  useEffect(() => {
    const fetchRoomTypes = async () => {
      try {
        const { data } = await getRoomTypes();
        const types = data.results || data;
        setRoomTypes(types);

        // Generate placeholder images for each room type
        const images = {};
        types.forEach(type => {
          const name = type.name.toLowerCase();
          if (name === 'standard') {
            images[type.id] = { bg: 'linear-gradient(135deg, #dbeafe 0%, #bfdbfe 100%)', accent: '#1e5fa8', icon: '🛏️' };
          } else if (name === 'deluxe') {
            images[type.id] = { bg: 'linear-gradient(135deg, #fef3c7 0%, #fde68a 100%)', accent: '#92400e', icon: '✨' };
          } else if (name === 'suite') {
            images[type.id] = { bg: 'linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)', accent: '#065f46', icon: '👑' };
          } else {
            images[type.id] = { bg: 'linear-gradient(135deg, #f3e8ff 0%, #e9d5ff 100%)', accent: '#7c3aed', icon: '🏨' };
          }
        });
        setRoomTypeImages(images);
      } catch (error) {
        console.error('Error fetching room types:', error);
      } finally {
        setTypesLoading(false);
      }
    };
    fetchRoomTypes();
  }, []);

  // Parallax scroll effect
  useEffect(() => {
    const handleScroll = () => {
      if (heroRef.current) {
        const scrolled = window.pageYOffset;
        heroRef.current.style.transform = `translateY(${scrolled * 0.5}px)`;
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Helper function to format price
  const formatPrice = (price) => {
    return `₱${Number(price).toLocaleString()}/night`;
  };

  // Helper function to get description based on room type
  const getRoomDescription = (typeName) => {
    const name = typeName.toLowerCase();
    if (name === 'standard') {
      return 'Comfortable and well-appointed rooms with all essential amenities for a perfect stay.';
    } else if (name === 'deluxe') {
      return 'Spacious rooms with premium furnishings, enhanced amenities, and stunning views.';
    } else if (name === 'suite') {
      return 'The pinnacle of luxury — expansive suites with separate living areas and exclusive perks.';
    } else {
      return `Experience our luxurious ${typeName} rooms with premium amenities and exceptional service.`;
    }
  };

  // Scroll to section
  const scrollToSection = (sectionId) => {
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  return (
    <div>
      {/* Hero Section with Enhanced Effects */}
      <section
        ref={heroRef}
        style={{
          minHeight: '100vh',
          position: 'relative',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          background: 'linear-gradient(160deg, #0a1e3d 0%, #0f2b4c 40%, #1a3a5c 100%)',
          overflow: 'hidden',
        }}
      >
        {/* Animated decorative elements */}
        <div style={{
          position: 'absolute',
          top: '10%',
          left: '5%',
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(201,168,76,0.1) 0%, transparent 70%)',
          animation: 'pulse 4s ease-in-out infinite',
          pointerEvents: 'none'
        }} />
        <div style={{
          position: 'absolute',
          bottom: '15%',
          right: '8%',
          width: 400,
          height: 400,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(30,95,168,0.15) 0%, transparent 70%)',
          animation: 'pulse 5s ease-in-out infinite reverse',
          pointerEvents: 'none'
        }} />

        {/* Floating particles */}
        {[...Array(20)].map((_, i) => (
          <div
            key={i}
            style={{
              position: 'absolute',
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 4 + 2}px`,
              height: `${Math.random() * 4 + 2}px`,
              background: `rgba(255, 255, 255, ${Math.random() * 0.3 + 0.1})`,
              borderRadius: '50%',
              animation: `float ${Math.random() * 10 + 5}s linear infinite`,
              animationDelay: `${Math.random() * 5}s`,
              pointerEvents: 'none'
            }}
          />
        ))}

        <div style={{
          position: 'relative',
          zIndex: 1,
          textAlign: 'center',
          padding: '0 24px',
          animation: 'fadeInUp 1s ease forwards'
        }}>
          <div style={{
            fontSize: '0.75rem',
            letterSpacing: '0.25em',
            color: '#c9a84c',
            textTransform: 'uppercase',
            marginBottom: 20,
            fontWeight: 600,
            animation: 'slideInLeft 0.8s ease forwards'
          }}>
            Welcome to Grand Azure
          </div>
          <h1 style={{
            fontFamily: 'var(--font-display, "Playfair Display", serif)',
            fontSize: 'clamp(2.5rem, 7vw, 5.5rem)',
            fontWeight: 300,
            color: 'white',
            lineHeight: 1.1,
            marginBottom: 20,
            animation: 'zoomIn 0.8s ease forwards'
          }}>
            Where Luxury<br />
            <em style={{
              fontStyle: 'italic',
              background: 'linear-gradient(135deg, #c9a84c, #ffd700)',
              backgroundClip: 'text',
              WebkitBackgroundClip: 'text',
              color: 'transparent'
            }}>Meets Comfort</em>
          </h1>
          <p style={{
            color: 'rgba(255,255,255,0.85)',
            fontSize: 'clamp(0.9rem, 2vw, 1.1rem)',
            maxWidth: 600,
            margin: '0 auto',
            lineHeight: 1.8,
            animation: 'fadeInUp 0.8s ease 0.2s forwards',
            opacity: 0
          }}>
            Discover an unparalleled experience of elegance and hospitality in the heart of Cagayan de Oro.
          </p>

          <div style={{
            display: 'flex',
            gap: 16,
            justifyContent: 'center',
            marginTop: 40,
            animation: 'fadeInUp 0.8s ease 0.4s forwards',
            opacity: 0
          }}>
            <button
              onClick={() => scrollToSection('rooms')}
              style={{
                padding: '14px 32px',
                background: 'linear-gradient(135deg, #c9a84c 0%, #b8923e 100%)',
                border: 'none',
                borderRadius: 50,
                color: 'white',
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'all 0.3s',
                fontSize: '0.95rem'
              }}
              onMouseEnter={e => {
                e.currentTarget.style.transform = 'translateY(-2px)';
                e.currentTarget.style.boxShadow = '0 10px 20px rgba(0,0,0,0.2)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              Explore Rooms
            </button>
            <button
              onClick={() => scrollToSection('features')}
              style={{
                padding: '14px 32px',
                background: 'transparent',
                border: '2px solid #c9a84c',
                borderRadius: 50,
                color: '#c9a84c',
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'all 0.3s',
                fontSize: '0.95rem'
              }}
              onMouseEnter={e => {
                e.currentTarget.style.background = 'rgba(201,168,76,0.1)';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }}
              onMouseLeave={e => {
                e.currentTarget.style.background = 'transparent';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              Learn More ↓
            </button>
          </div>
        </div>

        {/* Scroll indicator */}
        <div style={{
          position: 'absolute',
          bottom: 30,
          left: '50%',
          transform: 'translateX(-50%)',
          animation: 'bounce 2s infinite',
          cursor: 'pointer'
        }}
        onClick={() => scrollToSection('features')}>
          <div style={{
            width: 30,
            height: 50,
            border: '2px solid rgba(255,255,255,0.3)',
            borderRadius: 20,
            position: 'relative'
          }}>
            <div style={{
              width: 4,
              height: 10,
              background: '#c9a84c',
              borderRadius: 2,
              position: 'absolute',
              top: 8,
              left: '50%',
              transform: 'translateX(-50%)',
              animation: 'scrollIndicator 2s infinite'
            }} />
          </div>
        </div>
      </section>

      {/* Features Section with Enhanced Cards */}
      <section id="features" className="section" style={{ background: 'white', padding: '80px 0' }}>
        <div className="container" style={{ textAlign: 'center', maxWidth: 1200, margin: '0 auto', padding: '0 24px' }}>
          <div style={{
            fontSize: '0.75rem',
            letterSpacing: '0.2em',
            color: '#1e5fa8',
            textTransform: 'uppercase',
            marginBottom: 12,
            fontWeight: 600
          }}>
            Why Choose Us
          </div>
          <h2 className="section-title" style={{
            marginBottom: 16,
            fontSize: 'clamp(1.8rem, 5vw, 2.5rem)',
            color: '#0a1e3d'
          }}>
            The Grand Azure Experience
          </h2>
          <p style={{
            color: '#6b7280',
            maxWidth: 600,
            margin: '0 auto 48px',
            fontSize: '1rem'
          }}>
            Experience world-class hospitality with our premium amenities and services
          </p>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 32
          }}>
            {[
